package main

import (
	"context"
	"fmt"
	"net/http"
	"net/http/httputil"
	"net/url"
	"strings"
	"time"
)

var (
	allowedHosts = map[string]bool{
		"api.partner1.com": true,
		"api.partner2.com": true,
		"api.partner3.com": true,
	}
	proxyTimeout = 30 * time.Second
)

func webhookProxyHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Get URL from query parameter
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter is required", http.StatusBadRequest)
		return
	}

	// Validate and sanitize URL
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		http.Error(w, "Invalid URL", http.StatusBadRequest)
		return
	}

	// Check if host is allowed
	if !isHostAllowed(parsedURL.Host) {
		http.Error(w, "Host not allowed", http.StatusForbidden)
		return
	}

	// Create context with timeout
	ctx, cancel := context.WithTimeout(r.Context(), proxyTimeout)
	defer cancel()

	// Create new request with context
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, targetURL, nil)
	if err != nil {
		http.Error(w, "Failed to create request", http.StatusInternalServerError)
		return
	}

	// Copy headers from original request
	for name, values := range r.Header {
		for _, value := range values {
			req.Header.Add(name, value)
		}
	}

	// Create HTTP client
	client := &http.Client{
		Timeout: proxyTimeout,
	}

	// Make request
	resp, err := client.Do(req)
	if err != nil {
		http.Error(w, fmt.Sprintf("Failed to fetch URL: %v", err), http.StatusBadGateway)
		return
	}
	defer resp.Body.Close()

	// Copy response headers
	for name, values := range resp.Header {
		for _, value := range values {
			w.Header().Add(name, value)
		}
	}

	// Set status code
	w.WriteHeader(resp.StatusCode)

	// Copy response body
	_, err = fmt.Fcopy(w, resp.Body)
	if err != nil {
		// Log error but don't return it to client
		fmt.Printf("Error copying response body: %v\n", err)
	}
}

func isHostAllowed(host string) bool {
	// Remove port if present
	host = strings.Split(host, ":")[0]
	return allowedHosts[host]
}

func main() {
	http.HandleFunc("/proxy", webhookProxyHandler)
	
	// Start server
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}